using namespace std;

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    vector<long long> ans;
    for (auto& q : queries) {
        long long l = q[0], r = q[1], t = q[2];
        unordered_map<long long, int> freq;
        for (long long i = l; i <= r; ++i) {
            freq[nums[i]]++;
        }
        long long max_freq = -1;
        long long max_elem = -1;
        for (auto& [key, count] : freq) {
            if (count >= t) {
                if (count > max_freq || (count == max_freq && key < max_elem)) {
                    max_freq = count;
                    max_elem = key;
                }
            }
        }
        ans.push_back(max_elem);
    }
    return ans;
}

