```javascript
function solve(nums, queries) {
    const ans = [];
    for (const q of queries) {
        const l = q[0], r = q[1], t = q[2];
        const freq = new Map();
        for (let i = l; i <= r; i++) {
            const num = nums[i];
            freq.set(num, (freq.get(num) || 0) + 1);
        }
        let maxFreq = -1;
        let maxElem = -1;
        for (const [key, count] of freq.entries()) {
            if (count >= t) {
                if (count > maxFreq || (count === maxFreq && key < maxElem)) {
                    maxFreq = count;
                    maxElem = key;
                }
            }
        }
        ans.push(maxElem);
    }
    return ans;
}
```

